        \alpha^{\text{Co}}_s = \frac{C_{\text{Co}}(s)}{\sqrt{\sum_{s'} C_{\text{Co}}(s')^2}} \quad \text{and} \quad Q_{\text{Co}}(s) = |\alpha^{\text{Co}}_s|^2.
        \label{eq:prob_co}
    \end{equation}
